// Pre-process: Combine all instructions + config + user KB into ONE system prompt
// IMPORTANT: Build the full system prompt here in JS to avoid n8n's {{ }} template
// engine stripping $$ to $ (n8n treats $$ as escape for literal $)
const webhook = $('PA Webhook').first().json;
const allInstructions = $('Load All Instructions').all();
const config = $('Get Agent Config').first().json || {};
const userKB = $('Pre-Fetch User KB').all();

// Build instructions from all loaded files
let instructions = '## INSTRUCTIONS\n\n';
for (const item of allInstructions) {
  const doc = item.json;
  if (doc.document) {
    instructions += `### ${doc.source_file}\n\n${doc.document}\n\n---\n\n`;
  }
}

// Build user knowledge base section (always-on RAG)
let kbSection = '';
if (userKB.length > 0 && userKB[0].json.document) {
  kbSection = '## USER KNOWLEDGE BASE\n\n';
  for (const item of userKB) {
    if (item.json.document) {
      kbSection += `[${item.json.category || 'general'}]: ${item.json.document}\n\n`;
    }
  }
  kbSection += '---\n\n';
}

// Append KB to instructions
instructions += kbSection;

// Build the FULL system prompt here (not in n8n {{ }} templates)
// This preserves $$ characters that n8n templates would strip
const userSettingsStr = config.user_settings
  ? JSON.stringify(config.user_settings, null, 2)
  : 'NOT SET - This is a first-time agent setup. Collect all settings and include user_settings in your response.';

const systemPrompt = instructions + '\n\n---\n\n' +
  '## AGENT/SYSTEM CONFIG:\n\n' +
  '### Enabled Agents:\n' + (config.enabled_agents || '') + '\n\n' +
  '### Available Assistants:\n' + (config.assistants || '') + '\n\n' +
  '### Agent ID Mapping:\n' + (config.agent_department_value || '') + '\n\n' +
  '### User Settings (for agent onboarding reuse):\n' + userSettingsStr + '\n\n' +
  '---\n\n' +
  '## TOOLS:\n\n' +
  '### Knowledge Base Tools:\n' +
  '- **Vector Search** - Find info from KB (categories: company_overview, icp_target_audience, branding_identity, messaging_positioning, product_services, sales_process, marketing_channels, development_technical, operations_workflows, contacts_stakeholders, customer_success, competitive_landscape, documents)\n' +
  '- **Save to KB** - Store NEW information or extracted file content into a KB category\n' +
  '- **Update KB** - Correct/update EXISTING info with granular find-and-replace (requires old_content + new_content)\n' +
  '- **Delete from KB** - Remove specific entry by category and content match\n' +
  '- **Upload File** - Process file (.pdf, .txt, .md, .json, .docx) and store in KB. ALWAYS use when user uploads a file or a Supabase storage URL is in the message.\n\n' +
  '### Agent Setup Tools:\n' +
  '- **Save User Settings** - Save to profiles table (FIRST agent only: brand_voice, target_audience, primary_goals as comma-separated string, calendar_type, notifications_enabled)\n' +
  '- **Enable Agent** - Insert into assistant_personalizations with is_enabled=true (agent_id e.g. newsletter_multi, smm, content_repurposer, sol)\n' +
  '- **Get Agent Setup** - Check agent config from assistant_personalizations before redirect/onboarding\n\n' +
  '### Other Tools:\n' +
  '- **Web Analysis** - Scrape and analyze website URL for company info, products, brand voice';

const body = webhook.body || {};

return {
  json: {
    user_id: body.user_id,
    session_id: body.session_id,
    user_mssg: (body.user_mssg || '').trim(),
    agent_name: body.agent_name || 'personal_assistant',
    request_id: body.request_id || crypto.randomUUID(),
    timestamp: new Date().toISOString(),
    system_prompt: systemPrompt,
    instructions: instructions || 'No instructions found.',
    enabled_agents: config.enabled_agents || '',
    assistants: config.assistants || '',
    values_not_enabled: config.values_not_enabled || '',
    agent_department_value: config.agent_department_value || '',
    website_analysis_info: config.website_analysis_info || '',
    brand_voices: config.brand_voices || '',
    target_audiences: config.target_audiences || '',
    primary_goals: config.primary_goals || '',
    calendar_types: config.calendar_types || '',
    notification_options: config.notification_options || '',
    business_types: config.business_types || '',
    has_completed_onboarding: config.has_completed_onboarding || false
  }
};

// Response Builder: Format AI output for webhook response
const preProcess = $('Pre-Process').first().json;
const aiOutput = $input.first().json.output || $input.first().json.text || '';

// Initialize all possible fields
let message = aiOutput;
let routing = null;
let finished = false;
let agentData = null;
let actionsPerformed = [];
let actionsTodo = [];
let preview = null;
let userSettings = null;
let reusedSettings = false;

try {
  // Check if output is JSON
  if (aiOutput.trim().startsWith('{')) {
    const parsedOutput = JSON.parse(aiOutput);

    // Core fields
    message = parsedOutput.message || parsedOutput.response || aiOutput;
    routing = parsedOutput.routing || null;
    finished = parsedOutput.finished || false;
    agentData = parsedOutput.agent_data || null;

    // Actions tracking
    actionsPerformed = parsedOutput.actions_performed || [];
    actionsTodo = parsedOutput.actions_todo || [];

    // Content preview
    preview = parsedOutput.preview || null;

    // User settings (for first agent setup)
    userSettings = parsedOutput.user_settings || null;
    reusedSettings = parsedOutput.reused_settings || false;
  }
} catch (e) {
  // Not JSON, use as plain text
  message = aiOutput;
}

// Build standardized response
const response = {
  // Request tracking
  user_id: preProcess.user_id,
  session_id: preProcess.session_id,
  agent_name: preProcess.agent_name,
  timestamp_of_call_made: preProcess.timestamp,
  request_id: preProcess.request_id,

  // Main response
  agent_response: message,

  // Actions tracking (always include, even if empty)
  actions_performed: actionsPerformed,
  actions_todo: actionsTodo
};

// Add routing if present (for redirects)
if (routing) {
  response.routing = routing;
}

// Add preview if present (for content display)
if (preview) {
  response.preview = preview;
}

// Add agent_data if present (for onboarding completion)
if (finished) {
  response.finished = finished;
  if (agentData) {
    response.agent_data = agentData;
  }
}

// Add user_settings if present (for first agent setup - backend will save)
if (userSettings) {
  response.user_settings = userSettings;
}

// Add reused_settings flag if agent reused existing settings
if (reusedSettings) {
  response.reused_settings = true;
}

return { json: response };
